package cmd

import (
	"context"
	"strings"
	"sync/atomic"
	"testing"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/DocumentDrivenDX/ddx/internal/escalation"
)

// These tests exercise the cost-cap and infrastructure-failure wiring used
// by runAgentExecuteLoop's executor closure. The closure itself is built
// inline (so it cannot be unit-tested directly), but we exercise the same
// composition pattern here against a fake inner attempt to assert:
//
//  1. When accumulated cost exceeds the cap, the next executor invocation
//     returns the cap-tripped error WITHOUT invoking the inner attempt.
//  2. Infrastructure failures do not escalate to a smart tier — the tier
//     loop short-circuits with a deferred RetryAfter.
//
// The patterns mirror the closures in cli/cmd/agent_cmd.go (ddx-785d02f7).

// fakeAttempt records calls and returns a configured sequence of reports.
type fakeAttempt struct {
	calls   atomic.Int32
	reports []agent.ExecuteBeadReport
}

func (f *fakeAttempt) next(_ string) agent.ExecuteBeadReport {
	idx := f.calls.Add(1) - 1
	if int(idx) >= len(f.reports) {
		return f.reports[len(f.reports)-1]
	}
	return f.reports[idx]
}

// buildCostCappedExecutor mirrors the outer-executor wrapping done in
// runAgentExecuteLoop: cap check at the top, inner attempt, accumulate,
// cap check on the way out. Used by the tests below.
func buildCostCappedExecutor(tracker *escalation.CostCapTracker, inner func(beadID string) agent.ExecuteBeadReport) agent.ExecuteBeadExecutorFunc {
	return func(ctx context.Context, beadID string) (agent.ExecuteBeadReport, error) {
		if detail, capped := tracker.Tripped(); capped {
			return agent.ExecuteBeadReport{
				BeadID: beadID,
				Status: agent.ExecuteBeadStatusExecutionFailed,
				Detail: detail,
			}, nil
		}
		report := inner(beadID)
		tracker.Add(report.Harness, report.CostUSD)
		if detail, capped := tracker.Tripped(); capped {
			return agent.ExecuteBeadReport{
				BeadID: beadID,
				Status: agent.ExecuteBeadStatusExecutionFailed,
				Detail: detail,
			}, nil
		}
		return report, nil
	}
}

// TestExecuteLoopCostCap_ShortCircuitsAfterCap asserts the cost cap halts
// the queue: once accumulated billed cost reaches the cap, the next
// executor call returns the cap-tripped status without invoking the
// inner attempt.
func TestExecuteLoopCostCap_ShortCircuitsAfterCap(t *testing.T) {
	tracker := escalation.NewCostCapTracker(10.0, func(string) bool { return true })

	fake := &fakeAttempt{
		reports: []agent.ExecuteBeadReport{
			{BeadID: "ddx-1", Harness: "openrouter", Status: agent.ExecuteBeadStatusSuccess, CostUSD: 6.0},
			{BeadID: "ddx-2", Harness: "openrouter", Status: agent.ExecuteBeadStatusSuccess, CostUSD: 6.0},
			// Should never be reached.
			{BeadID: "ddx-3", Harness: "openrouter", Status: agent.ExecuteBeadStatusSuccess, CostUSD: 1.0},
		},
	}
	exec := buildCostCappedExecutor(tracker, fake.next)

	// First call: $6 < $10 cap — succeeds and accumulates.
	r1, err := exec(context.Background(), "ddx-1")
	if err != nil {
		t.Fatalf("call 1 err = %v", err)
	}
	if r1.Status != agent.ExecuteBeadStatusSuccess {
		t.Fatalf("call 1 status = %s, want success", r1.Status)
	}

	// Second call: accumulates to $12 >= $10 cap. Returns success but
	// cap is now tripped — but wait, the post-attempt cap check fires,
	// returning the cap-tripped report instead of the success report.
	r2, err := exec(context.Background(), "ddx-2")
	if err != nil {
		t.Fatalf("call 2 err = %v", err)
	}
	if r2.Status != agent.ExecuteBeadStatusExecutionFailed {
		t.Fatalf("call 2 should have tripped post-attempt cap; status = %s", r2.Status)
	}
	if !strings.Contains(r2.Detail, "cost cap reached") {
		t.Fatalf("call 2 detail missing cost-cap message: %q", r2.Detail)
	}

	callsBefore := fake.calls.Load()

	// Third call: cap-on-entry check trips IMMEDIATELY, inner attempt
	// is NOT invoked.
	r3, err := exec(context.Background(), "ddx-3")
	if err != nil {
		t.Fatalf("call 3 err = %v", err)
	}
	if r3.Status != agent.ExecuteBeadStatusExecutionFailed {
		t.Fatalf("call 3 should be cap-tripped; status = %s", r3.Status)
	}
	if r3.BeadID != "ddx-3" {
		t.Fatalf("call 3 beadID = %s, want ddx-3", r3.BeadID)
	}
	if got := fake.calls.Load(); got != callsBefore {
		t.Fatalf("cap-on-entry must NOT invoke inner attempt; calls went %d -> %d", callsBefore, got)
	}
}

// TestExecuteLoopCostCap_LocalProvidersDoNotCount asserts that local
// and subscription providers' CostUSD never accumulates against the
// cap, even if they report a non-zero cost field.
func TestExecuteLoopCostCap_LocalProvidersDoNotCount(t *testing.T) {
	// Lookup says only "openrouter" counts.
	tracker := escalation.NewCostCapTracker(10.0, func(name string) bool {
		return name == "openrouter"
	})

	fake := &fakeAttempt{
		reports: []agent.ExecuteBeadReport{
			{BeadID: "ddx-a", Harness: "claude", Status: agent.ExecuteBeadStatusSuccess, CostUSD: 100.0},
			{BeadID: "ddx-b", Harness: "qwen-local", Status: agent.ExecuteBeadStatusSuccess, CostUSD: 100.0},
			{BeadID: "ddx-c", Harness: "openrouter", Status: agent.ExecuteBeadStatusSuccess, CostUSD: 1.0},
		},
	}
	exec := buildCostCappedExecutor(tracker, fake.next)

	for _, id := range []string{"ddx-a", "ddx-b", "ddx-c"} {
		r, err := exec(context.Background(), id)
		if err != nil {
			t.Fatalf("call %s err = %v", id, err)
		}
		if r.Status != agent.ExecuteBeadStatusSuccess {
			t.Fatalf("call %s status = %s, want success (local/sub providers must not trip the cap)", id, r.Status)
		}
	}
	if got := tracker.Spent(); got != 1.0 {
		t.Fatalf("Spent = %.2f, want 1.0 — only openrouter should contribute", got)
	}
}

// TestInfrastructureFailureDoesNotEscalate asserts that the
// infrastructure-failure check used by the tier-escalation loop in
// runAgentExecuteLoop short-circuits without consuming escalation
// budget. We verify the contract that:
//   - IsInfrastructureFailure(execution_failed, "502 Bad Gateway") is true,
//     so the loop body's infrastructure branch fires (deferred + RetryAfter).
//   - IsInfrastructureFailure(execution_failed, "TestFoo failed") is false,
//     so the loop falls through to mark the harness unhealthy and try the
//     next tier.
//
// This is a contract test — the actual tier-escalation closure is built
// inline in runAgentExecuteLoop. The two-arm decision in that closure
// (defer-vs-escalate) is driven entirely by IsInfrastructureFailure.
func TestInfrastructureFailureDoesNotEscalate(t *testing.T) {
	cases := []struct {
		name   string
		status string
		detail string
		// wantInfra=true means "defer with retry-after, do not escalate";
		// wantInfra=false means "escalate to next tier".
		wantInfra bool
	}{
		{"502 from provider triggers defer", agent.ExecuteBeadStatusExecutionFailed, "POST /v1/chat: 502 Bad Gateway", true},
		{"connection refused triggers defer", agent.ExecuteBeadStatusExecutionFailed, "dial tcp: connection refused", true},
		{"401 unauthorized triggers defer", agent.ExecuteBeadStatusExecutionFailed, "401 Unauthorized", true},
		{"plain test failure does NOT defer (escalates)", agent.ExecuteBeadStatusExecutionFailed, "TestFoo: assertion failed", false},
		{"structural failure escalates but is not infrastructure", "structural_validation_failed", "anything 502", false},
	}
	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			got := escalation.IsInfrastructureFailure(tc.status, tc.detail)
			if got != tc.wantInfra {
				t.Fatalf("IsInfrastructureFailure(%q, %q) = %v, want %v", tc.status, tc.detail, got, tc.wantInfra)
			}
			// Sanity: an infra failure on an escalatable status should
			// also have ShouldEscalate=true (so the loop body must
			// explicitly check infra BEFORE escalating).
			if tc.wantInfra && !escalation.ShouldEscalate(tc.status) {
				t.Fatalf("infrastructure-failure case %q has !ShouldEscalate; loop ordering invariant broken", tc.name)
			}
		})
	}
}

package server

import (
	"context"
	"strings"
	"sync/atomic"
	"testing"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/DocumentDrivenDX/ddx/internal/escalation"
)

// These tests exercise the cost-cap and infrastructure-failure wiring
// used by runWorker's executor closure (see workers.go around the
// `executor := agent.ExecuteBeadExecutorFunc(...)` block).
//
// The closure itself is built inline (so it cannot be unit-tested
// directly), but we exercise the same composition pattern here against
// a fake inner attempt to assert:
//
//  1. When accumulated cost exceeds the cap, the next executor call
//     returns the cap-tripped error WITHOUT invoking the inner attempt.
//  2. Infrastructure failures are detected by IsInfrastructureFailure
//     and short-circuit before the next-tier escalation step.
//
// Patterns mirror the closures in cli/internal/server/workers.go
// (ddx-785d02f7).

type fakeServerAttempt struct {
	calls   atomic.Int32
	reports []agent.ExecuteBeadReport
}

func (f *fakeServerAttempt) next(_ string) agent.ExecuteBeadReport {
	idx := f.calls.Add(1) - 1
	if int(idx) >= len(f.reports) {
		return f.reports[len(f.reports)-1]
	}
	return f.reports[idx]
}

func wrapServerExecutor(tracker *escalation.CostCapTracker, inner func(beadID string) agent.ExecuteBeadReport) agent.ExecuteBeadExecutorFunc {
	return func(ctx context.Context, beadID string) (agent.ExecuteBeadReport, error) {
		if detail, capped := tracker.Tripped(); capped {
			return agent.ExecuteBeadReport{
				BeadID: beadID,
				Status: agent.ExecuteBeadStatusExecutionFailed,
				Detail: detail,
			}, nil
		}
		report := inner(beadID)
		tracker.Add(report.Harness, report.CostUSD)
		if detail, capped := tracker.Tripped(); capped {
			return agent.ExecuteBeadReport{
				BeadID: beadID,
				Status: agent.ExecuteBeadStatusExecutionFailed,
				Detail: detail,
			}, nil
		}
		return report, nil
	}
}

// TestWorkerExecutorCostCap_StopsAfterCap asserts the server worker's
// cost-cap logic halts further bead claiming once accumulated billed
// spend reaches the cap.
func TestWorkerExecutorCostCap_StopsAfterCap(t *testing.T) {
	tracker := escalation.NewCostCapTracker(5.0, func(string) bool { return true })

	fake := &fakeServerAttempt{
		reports: []agent.ExecuteBeadReport{
			{BeadID: "ddx-1", Harness: "openrouter", Status: agent.ExecuteBeadStatusSuccess, CostUSD: 3.0},
			{BeadID: "ddx-2", Harness: "openrouter", Status: agent.ExecuteBeadStatusSuccess, CostUSD: 3.0},
			{BeadID: "ddx-3", Harness: "openrouter", Status: agent.ExecuteBeadStatusSuccess, CostUSD: 1.0},
		},
	}
	exec := wrapServerExecutor(tracker, fake.next)

	// First call: $3 < $5 cap.
	if r, err := exec(context.Background(), "ddx-1"); err != nil || r.Status != agent.ExecuteBeadStatusSuccess {
		t.Fatalf("call 1: status=%s err=%v", r.Status, err)
	}
	// Second call: $6 >= $5; post-attempt cap fires.
	r2, _ := exec(context.Background(), "ddx-2")
	if r2.Status != agent.ExecuteBeadStatusExecutionFailed {
		t.Fatalf("call 2 should trip cap; status=%s", r2.Status)
	}
	if !strings.Contains(r2.Detail, "cost cap reached") {
		t.Fatalf("call 2 detail = %q", r2.Detail)
	}

	callsBefore := fake.calls.Load()
	// Third call: cap-on-entry blocks before invoking inner.
	r3, _ := exec(context.Background(), "ddx-3")
	if r3.Status != agent.ExecuteBeadStatusExecutionFailed {
		t.Fatalf("call 3 should be cap-tripped on entry; status=%s", r3.Status)
	}
	if r3.BeadID != "ddx-3" {
		t.Fatalf("cap-tripped report missing beadID: %q", r3.BeadID)
	}
	if got := fake.calls.Load(); got != callsBefore {
		t.Fatalf("inner attempt was invoked despite cap; calls %d -> %d", callsBefore, got)
	}
}

// TestWorkerExecutorCostCap_SubscriptionDoesNotCount asserts that
// subscription/local-provider costs do not contribute to the cap, even
// at huge reported CostUSD values.
func TestWorkerExecutorCostCap_SubscriptionDoesNotCount(t *testing.T) {
	tracker := escalation.NewCostCapTracker(10.0, func(name string) bool {
		// Only "openrouter" counts; everything else is local/subscription.
		return name == "openrouter"
	})

	fake := &fakeServerAttempt{
		reports: []agent.ExecuteBeadReport{
			{BeadID: "ddx-x", Harness: "claude", Status: agent.ExecuteBeadStatusSuccess, CostUSD: 1000.0},
			{BeadID: "ddx-y", Harness: "openrouter", Status: agent.ExecuteBeadStatusSuccess, CostUSD: 1.0},
		},
	}
	exec := wrapServerExecutor(tracker, fake.next)

	for _, id := range []string{"ddx-x", "ddx-y"} {
		r, _ := exec(context.Background(), id)
		if r.Status != agent.ExecuteBeadStatusSuccess {
			t.Fatalf("call %s: subscription/billed mix should not trip; status=%s", id, r.Status)
		}
	}
	if got := tracker.Spent(); got != 1.0 {
		t.Fatalf("Spent = %.2f, want 1.0 (only openrouter counts)", got)
	}
}

// TestWorkerInfrastructureFailureDoesNotEscalate asserts the contract
// the server tier-loop relies on: IsInfrastructureFailure flags
// transient provider failures (so the loop defers with retry-after)
// without consuming escalation budget, while real model-capability
// failures fall through to the next-tier path.
func TestWorkerInfrastructureFailureDoesNotEscalate(t *testing.T) {
	cases := []struct {
		name      string
		status    string
		detail    string
		wantInfra bool
	}{
		{"503 from provider triggers defer", agent.ExecuteBeadStatusExecutionFailed, "503 service unavailable", true},
		{"i/o timeout triggers defer", agent.ExecuteBeadStatusExecutionFailed, "Get http://x: i/o timeout", true},
		{"missing binary triggers defer", agent.ExecuteBeadStatusExecutionFailed, `exec: "claude": executable file not found in $PATH`, true},
		{"build failure does NOT defer (escalates)", agent.ExecuteBeadStatusExecutionFailed, "build error: missing import", false},
		{"structural validation escalates but is not infra", "structural_validation_failed", "503 service unavailable", false},
	}
	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			got := escalation.IsInfrastructureFailure(tc.status, tc.detail)
			if got != tc.wantInfra {
				t.Fatalf("IsInfrastructureFailure(%q, %q) = %v, want %v", tc.status, tc.detail, got, tc.wantInfra)
			}
			// The loop ordering invariant: when IsInfrastructureFailure
			// returns true, ShouldEscalate must also be true (otherwise
			// the infra branch is unreachable from the tier loop).
			if tc.wantInfra && !escalation.ShouldEscalate(tc.status) {
				t.Fatalf("infra-failure case %q has !ShouldEscalate; loop ordering invariant broken", tc.name)
			}
		})
	}
}

package agent

import (
	"context"
	"encoding/json"
	"fmt"
	"io"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/DocumentDrivenDX/ddx/internal/escalation"
	"github.com/DocumentDrivenDX/ddx/internal/triage"
)

// triageDecisionEventKind is the event kind used to record the triage
// policy's chosen action after a non-APPROVE review verdict.
const triageDecisionEventKind = "triage-decision"

// PostMergeReviewInput bundles the data RunPostMergeReview needs from its
// caller — historically the execute-bead loop body, now the per-attempt
// pipeline owned by try.Attempt (ddx-a921ff01 C3). The fields mirror what
// the inlined block read from the worker, the candidate bead, the report,
// and the loop runtime.
type PostMergeReviewInput struct {
	Bead        bead.Bead
	Report      ExecuteBeadReport
	Reviewer    BeadReviewer
	Store       ExecuteBeadLoopStore
	ProjectRoot string
	Rcfg        config.ResolvedConfig
	NoReview    bool
	Log         io.Writer
	Assignee    string
	Now         func() time.Time
}

// PostMergeReviewOutput carries the review state machine's decision back to
// the caller. Report is the (possibly updated) ExecuteBeadReport; Approved
// reports whether the caller should treat this attempt as a success. When
// the review path encountered a non-fatal Store error the caller is expected
// to route StoreErr through its outcome-error handler
// (handleOutcomeStoreError on ExecuteBeadWorker), keyed by StoreErrOp.
type PostMergeReviewOutput struct {
	Report     ExecuteBeadReport
	Approved   bool
	StoreErrOp string
	StoreErr   error
}

// RunPostMergeReview executes the post-merge review state machine for a
// successful bead attempt. When review is skipped (no reviewer, --no-review,
// or the review:skip label) the bead is closed and the function returns
// Approved=true. Otherwise the reviewer is invoked, its verdict (or error)
// drives the canonical event emissions (review / review-error /
// review-manual-required / review-malfunction), and on a non-APPROVE verdict
// the bead is reopened and the triage policy is consulted via the private
// applyReviewTriageDecision callout that previously lived as a method on
// ExecuteBeadWorker.
//
// Returns Approved=true on the APPROVE path and on the skip path; returns
// Approved=false on REQUEST_CHANGES, BLOCK, malformed BLOCK, or reviewer
// transport error. Store errors are surfaced via StoreErrOp + StoreErr so
// callers can keep the existing handleOutcomeStoreError pattern unchanged.
//
// This is the C3 (ddx-a921ff01) extraction of the 180-line review block
// previously inline in execute_bead_loop.go; the loop now sees a structured
// outcome and conflict-recovery / decomposition / no_changes paths remain
// in the loop body until subsequent C-series beads (C4, C5) move them too.
func RunPostMergeReview(ctx context.Context, in PostMergeReviewInput) PostMergeReviewOutput {
	report := in.Report
	out := PostMergeReviewOutput{Report: report, Approved: true}

	now := in.Now
	if now == nil {
		now = time.Now
	}

	reviewSkipped := in.Reviewer == nil || in.NoReview || HasBeadLabel(in.Bead.Labels, "review:skip")

	if reviewSkipped {
		if err := in.Store.CloseWithEvidence(in.Bead.ID, report.SessionID, report.ResultRev); err != nil {
			out.StoreErrOp = "CloseWithEvidence"
			out.StoreErr = err
			return out
		}
		out.Report = report
		return out
	}

	implRouting := ImplementerRouting{
		Harness:     report.Harness,
		Provider:    report.Provider,
		Model:       report.Model,
		ActualPower: report.ActualPower,
		Correlation: map[string]string{
			"bead_id":    in.Bead.ID,
			"attempt_id": report.AttemptID,
			"session_id": report.SessionID,
			"result_rev": report.ResultRev,
		},
	}
	reviewRes, reviewErr := in.Reviewer.ReviewBead(ctx, in.Bead.ID, report.ResultRev, implRouting)
	if reviewErr != nil {
		// FEAT-022 §12+§14: classify the failure into the four-class
		// taxonomy and count prior review-error events scoped to the
		// current result_rev. On the Nth failure emit a terminal
		// review-manual-required event instead of yet another
		// review-error, parking the bead so a subsequent loop
		// iteration does NOT re-execute primary.
		class := ClassifyReviewError(reviewErr, reviewRes)
		prior := CountPriorReviewErrors(in.Store, in.Bead.ID, report.ResultRev)
		attemptCount := prior + 1
		maxRetries := in.Rcfg.ReviewMaxRetries()
		if maxRetries <= 0 {
			maxRetries = DefaultReviewMaxRetries
		}
		errSummary := EventBodySummary{
			InputBytes:  0,
			OutputBytes: 0,
		}
		if reviewRes != nil {
			errSummary = EventBodySummary{
				Harness:     reviewRes.ReviewerHarness,
				Model:       reviewRes.ReviewerModel,
				InputBytes:  reviewRes.InputBytes,
				OutputBytes: reviewRes.OutputBytes,
				ElapsedMS:   reviewRes.DurationMS,
			}
		}
		if attemptCount >= maxRetries {
			body := AppendEventSummary(ReviewErrorEventBody(class, attemptCount, report.ResultRev, reviewErr.Error()), errSummary)
			_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
				Kind:      "review-manual-required",
				Summary:   class,
				Body:      body,
				Actor:     in.Assignee,
				Source:    "ddx agent execute-loop",
				CreatedAt: now().UTC(),
			})
			// Park the bead with a long cooldown so subsequent
			// loop iterations do NOT re-pick it for primary
			// re-execution. Reviewer-failure invariant (§13) is
			// preserved: the bead is NOT closed.
			parkUntil := now().UTC().Add(CapLoopCooldown(MaxLoopCooldown))
			_ = in.Store.SetExecutionCooldown(in.Bead.ID, parkUntil, "review-manual-required", class)
		} else {
			body := AppendEventSummary(ReviewErrorEventBody(class, attemptCount, report.ResultRev, reviewErr.Error()), errSummary)
			_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
				Kind:      "review-error",
				Summary:   class,
				Body:      body,
				Actor:     in.Assignee,
				Source:    "ddx agent execute-loop",
				CreatedAt: now().UTC(),
			})
		}
		out.Report = report
		out.Approved = false
		return out
	}

	report.ReviewVerdict = string(reviewRes.Verdict)
	report.ReviewRationale = reviewRes.Rationale
	// Persist the full reviewer stream as an artifact so the
	// event body never carries the raw stream (ddx-f8a11202).
	// On error the artifact path is empty and the event body
	// still contains the short verdict summary; callers of this
	// loop can recover the full text from the reviewer session
	// log if the artifact write failed.
	artifactPath, artifactErr := PersistReviewerStream(in.ProjectRoot, in.Bead.ID, report.AttemptID, reviewRes.RawOutput)
	if artifactErr != nil && in.Log != nil {
		_, _ = fmt.Fprintf(in.Log, "reviewer stream artifact: %v\n", artifactErr)
	}

	reviewSummary := EventBodySummary{
		Harness:     reviewRes.ReviewerHarness,
		Model:       reviewRes.ReviewerModel,
		InputBytes:  reviewRes.InputBytes,
		OutputBytes: reviewRes.OutputBytes,
		ElapsedMS:   reviewRes.DurationMS,
	}
	switch reviewRes.Verdict {
	case VerdictApprove:
		// Approved: record the verdict event and then close.
		// Closure must land AFTER the review event so the
		// gate (ddx-e30e60a9) sees the terminal verdict.
		_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
			Kind:      "review",
			Summary:   "APPROVE",
			Body:      AppendEventSummary(ReviewEventBody("APPROVE", reviewRes.Rationale, artifactPath), reviewSummary),
			Actor:     in.Assignee,
			Source:    "ddx agent execute-loop",
			CreatedAt: now().UTC(),
		})
		if cerr := in.Store.CloseWithEvidence(in.Bead.ID, report.SessionID, report.ResultRev); cerr != nil {
			out.Report = report
			out.StoreErrOp = "CloseWithEvidence"
			out.StoreErr = cerr
			return out
		}
	case VerdictRequestChanges:
		// Needs fixes: record the review verdict, then reopen
		// with findings in notes. The review event must land
		// even on non-approve paths so review-outcomes can
		// attribute the rejection to the originating tier.
		_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
			Kind:      "review",
			Summary:   "REQUEST_CHANGES",
			Body:      AppendEventSummary(ReviewEventBody("REQUEST_CHANGES", reviewRes.Rationale, artifactPath), reviewSummary),
			Actor:     in.Assignee,
			Source:    "ddx agent execute-loop",
			CreatedAt: now().UTC(),
		})
		reopenNotes := reviewRes.Rationale
		if reopenNotes == "" {
			reopenNotes = reviewRes.RawOutput
		}
		if reopenErr := in.Store.Reopen(in.Bead.ID, "review: REQUEST_CHANGES", reopenNotes); reopenErr != nil {
			out.Report = report
			out.StoreErrOp = "Reopen"
			out.StoreErr = reopenErr
			return out
		}
		report.Status = ExecuteBeadStatusReviewRequestChanges
		report.Detail = "post-merge review: REQUEST_CHANGES"
		out.Approved = false
	case VerdictBlock:
		rationale := strings.TrimSpace(reviewRes.Rationale)
		if rationale == "" {
			_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
				Kind:      "review-malfunction",
				Summary:   "BLOCK without rationale",
				Body:      AppendEventSummary(ReviewEventBody("BLOCK without rationale", "", artifactPath), reviewSummary),
				Actor:     in.Assignee,
				Source:    "ddx agent execute-loop",
				CreatedAt: now().UTC(),
			})
			report.Status = ExecuteBeadStatusReviewMalfunction
			report.Detail = "post-merge review: malformed BLOCK verdict (missing rationale)"
			report.ReviewRationale = ""
			out.Report = report
			out.Approved = false
			return out
		}
		// Cannot proceed: record the verdict, then reopen and
		// flag for human with BLOCK marker plus actionable rationale.
		_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
			Kind:      "review",
			Summary:   "BLOCK",
			Body:      AppendEventSummary(rationale, reviewSummary),
			Actor:     in.Assignee,
			Source:    "ddx agent execute-loop",
			CreatedAt: now().UTC(),
		})
		blockNotes := "REVIEW:BLOCK\n\n" + rationale
		if reopenErr := in.Store.Reopen(in.Bead.ID, "review: BLOCK", blockNotes); reopenErr != nil {
			out.Report = report
			out.StoreErrOp = "Reopen"

package agent

import (
	"bytes"
	"context"
	"fmt"
	"os"
	"path"
	"path/filepath"
	"sort"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
